function setLanguage(lang){
  document.querySelectorAll('[data-i18n]').forEach(el=>{
    const dict=translations[lang],key=el.dataset.i18n;
    if(dict && dict[key]!==undefined) el.textContent=dict[key];
  });
  document.querySelectorAll('[data-i18n-ph]').forEach(el=>{
    const dict=translations[lang],key=el.dataset.i18nPh;
    if(dict && dict[key]!==undefined) el.setAttribute('placeholder',dict[key]);
  });
  document.querySelectorAll('.lang-switch button').forEach(b=>b.classList.toggle('active', b.dataset.lang===lang));
  document.documentElement.setAttribute('lang', lang==='zh'?'zh-CN':lang);
  window.currentLang=lang;
  try{localStorage.setItem('pgn_lang', lang);}catch(e){}
}
window.translations=translations;
window.setLanguage=setLanguage;

document.addEventListener('DOMContentLoaded',()=>{
  document.querySelectorAll('.lang-switch button').forEach(b=>{
    b.addEventListener('click', ()=>setLanguage(b.dataset.lang));
  });
  let savedLang='ru';
  try{savedLang=localStorage.getItem('pgn_lang')||'ru';}catch(e){}
  setLanguage(savedLang);
});
